<script>
const csrfToken=<?=json_encode(csrfToken())?>;
const purchaseId=<?=$id?>;
const currentFormat=<?=json_encode($format)?>;
const locked=<?=$locked?'true':'false'?>;
const providers=<?=json_encode($proveedores_db,JSON_UNESCAPED_UNICODE|JSON_HEX_TAG|JSON_HEX_AMP|JSON_HEX_APOS|JSON_HEX_QUOT)?>;
const poaOptions=<?=json_encode($poaOptions,JSON_UNESCAPED_UNICODE)?>;
const accountOptions=<?=json_encode($cuentasOptions,JSON_UNESCAPED_UNICODE)?>;
const presentations=<?=json_encode($presentaciones,JSON_UNESCAPED_UNICODE)?>;
const savedPlanillas=<?=json_encode($planillas,JSON_UNESCAPED_UNICODE|JSON_HEX_TAG|JSON_HEX_AMP|JSON_HEX_APOS|JSON_HEX_QUOT)?>;
const planillaOrderTotal=<?=json_encode((float)($purchase['monto_total']??0))?>;
const planillaPoaDefaults=<?=json_encode($planillaPoaDefaults,JSON_UNESCAPED_UNICODE|JSON_HEX_TAG|JSON_HEX_AMP|JSON_HEX_APOS|JSON_HEX_QUOT)?>;
let itemIndex=Math.max(<?=count($details)?>,1), summaryIndex=Math.max(<?=count($summaryRows)?>,0), poaIndex=Math.max(<?=count($poaDistribution)?>,0), planillaIndex=0;

function formatExplanation(format){const e=document.getElementById('formatExplanation');const map={A:'<strong>Forma A:</strong> compra directa con un proveedor. Conserva solicitud, orden, imputación, autorización y recepción.',B:'<strong>Forma B:</strong> añade un resumen comparativo de cuatro cotizaciones. Su resumen comparativo se imprime horizontal y los demás documentos permanecen verticales.',C:'<strong>Forma C:</strong> conserva internamente la lógica de la Forma A. Imprime transferencias y recibos verticales, y la planilla seleccionada en orientación horizontal; programa y marco lógico provienen del POA.'};e.innerHTML=map[format]||map.A}
formatExplanation(currentFormat);
document.getElementById('formatSelectorTop').addEventListener('change',function(){document.getElementById('formatHidden').value=this.value;formatExplanation(this.value);if(!purchaseId){document.querySelectorAll('[data-format-only]').forEach(el=>el.style.display=el.dataset.formatOnly===this.value?'':'none')}});

const CREATE_PROVIDER_VALUE='__CREATE_PROVIDER__';let providerTargetSelect=null;
function initSelect2(scope=document){if(!window.jQuery)return;$(scope).find('.select2').each(function(){if(!$(this).hasClass('select2-hidden-accessible'))$(this).select2({width:'100%'});});$(scope).find('.select2-tags').each(function(){if(!$(this).hasClass('select2-hidden-accessible'))$(this).select2({width:'100%',tags:true,placeholder:'Buscar o escribir...'});});$(scope).find('.select2-poa').each(function(){if(!$(this).hasClass('select2-hidden-accessible'))$(this).select2({width:'100%',templateResult:formatPoaResult,templateSelection:function(item){return item.text;},dropdownAutoWidth:false,dropdownCssClass:'poa-select-dropdown'});});$(scope).find('.select2-modal').each(function(){if(!$(this).hasClass('select2-hidden-accessible'))$(this).select2({width:'100%',dropdownParent:$('#providerModal'),placeholder:'Seleccione...'});});$(scope).find('.provider-search').each(function(){const el=this;if(!$(el).hasClass('select2-hidden-accessible'))$(el).select2({width:'100%',placeholder:'Buscar proveedor...',allowClear:true});$(el).off('.providerPicker').on('select2:select.providerPicker',function(ev){const value=String(ev.params.data.id||'');if(value===CREATE_PROVIDER_VALUE){$(el).val(null).trigger('change.select2');openProviderModal(el);return;}applyProviderSelection(el,value);}).on('select2:clear.providerPicker',function(){applyProviderSelection(el,'');});});}
function formatPoaResult(item){if(!item.id)return item.text;const el=$(item.element),disp=Number(el.data('disp')||0);return $(`<div class="poa-option-compact"><strong>${item.text}</strong><small>Disponible: L. ${disp.toLocaleString('es-HN',{minimumFractionDigits:2,maximumFractionDigits:2})}</small></div>`)}
function initAccountSelects(scope=document){if(!window.jQuery)return;$(scope).find('.select2-account').each(function(){if(!$(this).hasClass('select2-hidden-accessible'))$(this).select2({width:'100%',placeholder:'Buscar cuenta contable...'});});}
$(function(){initSelect2();initAccountSelects();if(!purchaseId&&document.querySelectorAll('#itemsBody tr').length===0)addItemRow();bindCalculators();if(currentFormat==='C')renderPlanillas();calcPoaTotal();calcQuoteTotals();calcOrderTotals();document.querySelectorAll('.provider-search').forEach(el=>{const value=String(el.value||'');if(value&&value!==CREATE_PROVIDER_VALUE)applyProviderSelection(el,value,false);});const purchaseProvider=<?=json_encode((string)($purchase['proveedor']??''),JSON_UNESCAPED_UNICODE)?>;if(purchaseProvider)fillProviderBanking(providerByName(purchaseProvider));});

function navTab(tab,button){const panel=document.getElementById('tab-'+tab);if(!panel)return;document.querySelectorAll('.tab-panel').forEach(p=>p.classList.remove('active'));document.querySelectorAll('.tab-btn').forEach(b=>b.classList.remove('active'));panel.classList.add('active');button&&button.classList.add('active');if(purchaseId)history.replaceState({},'',`?id=${purchaseId}&tab=${tab}`)}
function addItemRow(){const body=document.getElementById('itemsBody');const i=itemIndex++;const opts=presentations.map(p=>`<option value="${escapeHtml(p)}">${escapeHtml(p)}</option>`).join('');const tr=document.createElement('tr');tr.innerHTML=`<td><input type="number" step="0.01" min="0.01" name="items[${i}][cantidad]" required></td><td><select class="select2-tags" name="items[${i}][presentacion]">${opts}</select></td><td><input name="items[${i}][articulo]" required></td><td><input name="items[${i}][caracteristicas]"></td><td><button type="button" class="btn danger small" onclick="this.closest('tr').remove()"><i class="fa-solid fa-trash"></i></button></td>`;body.appendChild(tr);initSelect2(tr)}
function escapeHtml(s){return String(s??'').replace(/[&<>"']/g,m=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#039;'}[m]))}

function addSummaryRow(extra=true){const body=document.getElementById('summaryBody'),i=summaryIndex++;const tr=document.createElement('tr');tr.innerHTML=`<input type="hidden" name="resumen[${i}][es_extra]" value="${extra?1:0}"><td>${i+1}</td><td><input type="number" step="0.01" name="resumen[${i}][cantidad]" value="0"></td><td><input name="resumen[${i}][presentacion]"></td><td><input name="resumen[${i}][articulo]"></td><td><input name="resumen[${i}][caracteristicas]"></td>${[1,2,3,4].map(p=>`<td><input class="quote-price quote-unit" type="number" step="0.01" min="0" name="resumen[${i}][precios][${p}][precio]" value="0"></td><td class="quote-total">L. <span class="quote-row-total">0.00</span></td><td><select name="resumen[${i}][precios][${p}][impuesto]"><option value="E">E</option><option value="G">G</option></select></td>`).join('')}<td><button type="button" class="btn danger small" onclick="this.closest('tr').remove();reindexSummary();calcQuoteTotals()"><i class="fa-solid fa-trash"></i></button></td>`;body.appendChild(tr);bindCalculators()}
function reindexSummary(){document.querySelectorAll('#summaryBody tr').forEach((tr,i)=>{const first=tr.querySelector('td');if(first)first.textContent=i+1})}
function calcQuoteTotals(){const table=document.getElementById('quoteTable');if(!table)return;const providerTotals={1:{sub:0,grav:0},2:{sub:0,grav:0},3:{sub:0,grav:0},4:{sub:0,grav:0}};table.querySelectorAll('tbody tr').forEach(tr=>{const qty=Number(tr.querySelector('input[name*="[cantidad]"]')?.value||0);[1,2,3,4].forEach((p,idx)=>{const unit=Number(tr.querySelector(`input[name*="[precios][${p}][precio]"]`)?.value||0);const tax=tr.querySelector(`select[name*="[precios][${p}][impuesto]"]`)?.value||'E';const total=qty*unit;const cells=tr.querySelectorAll('.quote-row-total');if(cells[idx])cells[idx].textContent=total.toFixed(2);providerTotals[p].sub+=total;if(tax==='G')providerTotals[p].grav+=total})});[1,2,3,4].forEach(p=>{const discount=Number(document.querySelector(`input[name="cotizaciones[${p-1}][descuento]"]`)?.value||0);const dGrav=providerTotals[p].sub?discount*(providerTotals[p].grav/providerTotals[p].sub):0;const total=providerTotals[p].sub-discount+Math.max(0,(providerTotals[p].grav-dGrav)*.15);const el=document.getElementById('providerTotal'+p);if(el)el.textContent='L. '+total.toLocaleString('es-HN',{minimumFractionDigits:2,maximumFractionDigits:2})})}

function calcOrderTotals(){const rows=document.querySelectorAll('#tab-orden tbody tr');let sub=0,grav=0;rows.forEach(tr=>{const p=tr.querySelector('.order-price');if(!p)return;const q=Number(p.dataset.qty||0),u=Number(p.value||0),total=q*u;tr.querySelector('.order-row-total').textContent='L. '+total.toLocaleString('es-HN',{minimumFractionDigits:2});sub+=total;if(tr.querySelector('.order-tax')?.value==='G')grav+=total});const discount=Number(document.getElementById('orderDiscount')?.value||0),dGrav=sub?discount*(grav/sub):0,isv=Math.max(0,(grav-dGrav)*.15),grand=sub-discount+isv;document.getElementById('orderSubtotal')&&(document.getElementById('orderSubtotal').textContent='L. '+sub.toLocaleString('es-HN',{minimumFractionDigits:2}));document.getElementById('orderTax')&&(document.getElementById('orderTax').textContent='L. '+isv.toLocaleString('es-HN',{minimumFractionDigits:2}));document.getElementById('orderGrand')&&(document.getElementById('orderGrand').textContent='L. '+grand.toLocaleString('es-HN',{minimumFractionDigits:2}))}

function bindCalculators(){document.querySelectorAll('.quote-unit,.quote-discount,#quoteTable select').forEach(e=>{e.oninput=calcQuoteTotals;e.onchange=calcQuoteTotals});document.querySelectorAll('.order-price,.order-tax,#orderDiscount').forEach(e=>{e.oninput=calcOrderTotals;e.onchange=calcOrderTotals});document.querySelectorAll('.poa-amount').forEach(e=>e.oninput=calcPoaTotal)}

function addPoaRow(){const body=document.getElementById('poaBody'),i=poaIndex++;const tr=document.createElement('tr');const remaining=Math.max(0,Number(<?=json_encode((float)($purchase['monto_total']??0))?>)-poaAssigned());tr.innerHTML=`<td><select class="form-control select2-poa" name="poa_lineas[${i}][hash]"><option value="">Seleccione...</option>${poaOptions}</select></td><td><select class="form-control select2-account" name="poa_lineas[${i}][cuenta_id]" required><option value="">Seleccione del catálogo...</option>${accountOptions}</select></td><td><input class="poa-amount" type="number" step="0.01" min="0" name="poa_lineas[${i}][monto]" value="${remaining.toFixed(2)}"></td><td><button type="button" class="btn danger small" onclick="this.closest('tr').remove();calcPoaTotal()" title="Eliminar línea"><i class="fa-solid fa-trash"></i></button></td>`;body.appendChild(tr);initSelect2(tr);initAccountSelects(tr);tr.querySelector('.poa-amount').oninput=calcPoaTotal;calcPoaTotal()}
function poaAssigned(){return [...document.querySelectorAll('.poa-amount')].reduce((s,e)=>s+Number(e.value||0),0)}
function calcPoaTotal(){const value=poaAssigned(),el=document.getElementById('poaAssigned');if(el){el.textContent='L. '+value.toLocaleString('es-HN',{minimumFractionDigits:2});el.style.color=Math.abs(value-Number(<?=json_encode((float)($purchase['monto_total']??0))?>))<.05?'#34d399':'#fbbf24'}}

function renderPlanillas(){const container=document.getElementById('planillasContainer');if(!container)return;container.innerHTML='';const list=savedPlanillas.length?savedPlanillas:[{plantilla:'COMISAL',nombre_cooperativa:'COOPERATIVA COMISAL',titulo:'PLANILLA DE INCENTIVOS A VOLUNTARIOS',programa:planillaPoaDefaults.programa,marco_logico:planillaPoaDefaults.marco_logico,comision_default:4,fecha_preparado:new Date().toISOString().slice(0,10),detalles:[{}]}];list.forEach(p=>addPlanilla(p))}
function addPlanilla(data={}){const container=document.getElementById('planillasContainer'),i=planillaIndex++;const card=document.createElement('div');card.className='planilla-card';card.dataset.index=i;card.innerHTML=`<div class="planilla-head"><strong><i class="fa-solid fa-table-list"></i> Planilla ${i+1}</strong>${locked?'':`<button type="button" class="btn danger small" onclick="this.closest('.planilla-card').remove();calcPlanillaTotals()"><i class="fa-solid fa-trash"></i></button>`}</div><div class="planilla-body"><div class="grid-4"><div class="form-group"><label>Plantilla</label><select class="form-control plan-template" name="planillas[${i}][plantilla]" ${locked?'disabled':''}><option value="COMISAL">COMISAL · Comisión 4%</option><option value="NUEVO_AMANECER">Nuevo Amanecer · Sin comisión</option><option value="GENERAL">General</option></select></div><div class="form-group"><label>Cooperativa / entidad</label><input class="form-control" name="planillas[${i}][nombre_cooperativa]" value="${escapeHtml(data.nombre_cooperativa||'')}" ${locked?'disabled':''}></div><div class="form-group"><label>Título</label><input class="form-control" name="planillas[${i}][titulo]" value="${escapeHtml(data.titulo||'')}" ${locked?'disabled':''}></div><div class="form-group"><label>Comisión por defecto (%)</label><input class="form-control default-commission" type="number" step="0.01" min="0" name="planillas[${i}][comision_default]" value="${Number(data.comision_default??0)}" ${locked?'disabled':''}></div></div><div class="grid-4"><div class="form-group"><label>Programa</label><input class="form-control" name="planillas[${i}][programa]" value="${escapeHtml(data.programa||'')}" ${locked?'disabled':''}></div><div class="form-group"><label>Marco lógico</label><input class="form-control" name="planillas[${i}][marco_logico]" value="${escapeHtml(data.marco_logico||'')}" ${locked?'disabled':''}></div><div class="form-group"><label>Fecha preparado</label><input class="form-control" type="date" name="planillas[${i}][fecha_preparado]" value="${escapeHtml(data.fecha_preparado||new Date().toISOString().slice(0,10))}" ${locked?'disabled':''}></div><div class="form-group"><label>Fecha pago</label><input class="form-control" type="date" name="planillas[${i}][fecha_pago]" value="${escapeHtml(data.fecha_pago||'')}" ${locked?'disabled':''}></div></div><div class="table-wrap"><table class="dynamic-table planilla-table"><thead><tr><th>#</th><th>Nombre</th><th>Comunidad</th><th>Identidad</th><th>Monto base</th><th>Comisión %</th><th>Comisión</th><th>Total transferencia</th><th>Instrucción</th>${locked?'':'<th></th>'}</tr></thead><tbody></tbody><tfoot><tr><th colspan="7">Total planilla</th><th class="plan-total">L. 0.00</th><th colspan="2"></th></tr></tfoot></table></div>${locked?'':`<button type="button" class="btn small" style="margin-top:10px" onclick="addPlanillaRow(${i})"><i class="fa-solid fa-plus"></i> Añadir beneficiario</button>`}</div>`;container.appendChild(card);const template=card.querySelector('.plan-template');template.value=data.plantilla||'GENERAL';template.onchange=()=>applyPlanillaTemplate(card);card.querySelector('.default-commission').oninput=()=>{card.querySelectorAll('.plan-commission-pct').forEach(e=>{if(!e.dataset.manual)e.value=card.querySelector('.default-commission').value});calcPlanillaTotals()};(data.detalles&&data.detalles.length?data.detalles:[{}]).forEach(r=>addPlanillaRow(i,r));}
function applyPlanillaTemplate(card){const type=card.querySelector('.plan-template').value,commission=card.querySelector('.default-commission');if(type==='COMISAL'){commission.value=4;card.querySelector('[name$="[nombre_cooperativa]"]').value='COOPERATIVA COMISAL'}else if(type==='NUEVO_AMANECER'){commission.value=0;card.querySelector('[name$="[nombre_cooperativa]"]').value='COOPERATIVA NUEVO AMANECER'}card.querySelectorAll('.plan-commission-pct').forEach(e=>{e.value=commission.value;e.dataset.manual=''});autoSinglePlanillaBase(card,true);calcPlanillaTotals()}
function addPlanillaRow(planIndex,data={}){const card=document.querySelector(`.planilla-card[data-index="${planIndex}"]`),body=card.querySelector('tbody'),r=body.children.length,defaultPct=Number(card.querySelector('.default-commission').value||0);const tr=document.createElement('tr');tr.innerHTML=`<td>${r+1}</td><td><input name="planillas[${planIndex}][detalles][${r}][nombre]" value="${escapeHtml(data.nombre||'')}" ${locked?'disabled':''}></td><td><input name="planillas[${planIndex}][detalles][${r}][comunidad]" value="${escapeHtml(data.comunidad||'')}" ${locked?'disabled':''}></td><td><input name="planillas[${planIndex}][detalles][${r}][identidad]" value="${escapeHtml(data.identidad||'')}" ${locked?'disabled':''}></td><td><input class="plan-base" type="number" step="0.01" min="0" name="planillas[${planIndex}][detalles][${r}][monto_base]" value="${Number(data.monto_base||0)}" ${locked?'disabled':''}></td><td><input class="plan-commission-pct" type="number" step="0.01" min="0" name="planillas[${planIndex}][detalles][${r}][comision_pct]" value="${Number(data.comision_pct??defaultPct)}" ${locked?'disabled':''}></td><td class="plan-commission">L. ${Number(data.comision||0).toFixed(2)}</td><td class="plan-transfer">L. ${Number(data.total_transferencia||0).toFixed(2)}</td><td><input name="planillas[${planIndex}][detalles][${r}][instruccion_pago]" value="${escapeHtml(data.instruccion_pago||'')}" ${locked?'disabled':''}></td>${locked?'':`<td><button type="button" class="btn danger small" onclick="this.closest('tr').remove();calcPlanillaTotals()"><i class="fa-solid fa-trash"></i></button></td>`}`;body.appendChild(tr);tr.querySelectorAll('.plan-base,.plan-commission-pct').forEach(e=>e.oninput=()=>{if(e.classList.contains('plan-commission-pct'))e.dataset.manual='1';calcPlanillaTotals()});calcPlanillaTotals()}
function autoSinglePlanillaBase(card,force=false){const rows=card.querySelectorAll('tbody tr');if(rows.length!==1||planillaOrderTotal<=0){rows.forEach(row=>{const base=row.querySelector('.plan-base');if(base&&!locked)base.readOnly=false});return}const base=rows[0].querySelector('.plan-base'),pct=Number(rows[0].querySelector('.plan-commission-pct')?.value||0);if(base){if(!locked)base.readOnly=true;if(force||Number(base.value||0)<=0)base.value=(planillaOrderTotal/(1+(pct/100))).toFixed(2)}}
function calcPlanillaTotals(){let all=0;document.querySelectorAll('.planilla-card').forEach(card=>{const program=card.querySelector('[name$="[programa]"]'),framework=card.querySelector('[name$="[marco_logico]"]');if(program){program.value=planillaPoaDefaults.programa||program.value;program.readOnly=true}if(framework){framework.value=planillaPoaDefaults.marco_logico||framework.value;framework.readOnly=true}autoSinglePlanillaBase(card,true);let total=0;card.querySelectorAll('tbody tr').forEach(tr=>{const base=Number(tr.querySelector('.plan-base')?.value||0),pct=Number(tr.querySelector('.plan-commission-pct')?.value||0),commission=Math.round(base*pct)/100,transfer=base+commission;tr.querySelector('.plan-commission').textContent='L. '+commission.toFixed(2);tr.querySelector('.plan-transfer').textContent='L. '+transfer.toFixed(2);total+=transfer});card.querySelector('.plan-total').textContent='L. '+total.toLocaleString('es-HN',{minimumFractionDigits:2});all+=total});return all}

function providerByName(name){const key=String(name||'').trim().toLocaleLowerCase('es');return providers.find(p=>String(p.nombre||'').trim().toLocaleLowerCase('es')===key)||null}
function safeProviderText(value){const v=String(value||'').trim();return v||'—'}
function setSelectValue(id,value){const el=document.getElementById(id);if(!el)return;const val=String(value||'');if(val&&!Array.from(el.options).some(o=>o.value===val))el.add(new Option(val,val,true,true));$(el).val(val).trigger('change.select2')}
function fillProviderInfoCard(provider){const map={providerInfoAddress:provider?.direccion,providerInfoBank:provider?.banco,providerInfoTransfer:provider?.tipo_transferencia,providerInfoAccountType:provider?.tipo_cuenta,providerInfoAccount:provider?.cuenta_bancaria};Object.entries(map).forEach(([id,value])=>{const el=document.getElementById(id);if(el)el.textContent=safeProviderText(value)})}
function fillProviderBanking(provider){const data=provider||{};const address=document.getElementById('providerAddressInput');if(address)address.value=data.direccion||'';setSelectValue('bankSelect',data.banco||'');setSelectValue('transferTypeSelect',data.tipo_transferencia||'');setSelectValue('accountTypeSelect',data.tipo_cuenta||'');const account=document.getElementById('accountNumberInput');if(account)account.value=data.cuenta_bancaria||''}
function updateProviderQuote(select,provider){const card=select.closest('.provider-card');if(!card)return;const rtn=card.querySelector('input[name$="[rtn]"]');if(rtn)rtn.value=provider?.rtn||'';const box=card.querySelector('[data-provider-info]');if(box)box.querySelectorAll('[data-field]').forEach(el=>el.textContent=safeProviderText(provider?.[el.dataset.field]))}
function applyProviderSelection(select,name,fillBanking=true){const provider=providerByName(name);if(select.id==='providerSelect'){const rtn=document.getElementById('providerRtn');if(rtn)rtn.value=provider?.rtn||'';fillProviderInfoCard(provider);if(fillBanking)fillProviderBanking(provider)}else updateProviderQuote(select,provider)}
function openProviderModal(target=null){providerTargetSelect=target||document.getElementById('providerSelect');const modal=document.getElementById('providerModal'),message=document.getElementById('providerModalMessage');if(message){message.className='provider-modal-message';message.textContent=''};['newProviderName','newProviderRtn','newProviderAddress','newProviderAccount'].forEach(id=>{const el=document.getElementById(id);if(el)el.value=''});['newProviderBank','newProviderTransfer','newProviderType'].forEach(id=>{const el=document.getElementById(id);if(el)$(el).val('').trigger('change.select2')});modal.style.display='flex';setTimeout(()=>document.getElementById('newProviderName')?.focus(),80)}
function closeProviderModal(){document.getElementById('providerModal').style.display='none';providerTargetSelect=null}
function appendProviderToSelects(provider){document.querySelectorAll('.provider-search').forEach(select=>{if(!Array.from(select.options).some(o=>o.value===provider.nombre)){const create=select.querySelector(`option[value="${CREATE_PROVIDER_VALUE}"]`),option=new Option(provider.nombre,provider.nombre,false,false);create?create.insertAdjacentElement('afterend',option):select.add(option)}})}
async function saveProviderModal(){const button=document.getElementById('saveProviderBtn'),message=document.getElementById('providerModalMessage'),provider={nombre:document.getElementById('newProviderName').value.trim(),rtn:document.getElementById('newProviderRtn').value.trim(),direccion:document.getElementById('newProviderAddress').value.trim(),banco:document.getElementById('newProviderBank').value,tipo_transferencia:document.getElementById('newProviderTransfer').value,tipo_cuenta:document.getElementById('newProviderType').value,cuenta_bancaria:document.getElementById('newProviderAccount').value.trim()};if(!provider.nombre){message.className='provider-modal-message error';message.textContent='Ingrese el nombre o razón social del proveedor.';return}button.disabled=true;button.innerHTML='<i class="fa-solid fa-spinner fa-spin"></i> Guardando...';try{const fd=new URLSearchParams({csrf_token:csrfToken,action:'guardar_nuevo_proveedor',...provider}),response=await fetch(location.pathname+location.search,{method:'POST',headers:{'Content-Type':'application/x-www-form-urlencoded;charset=UTF-8'},body:fd}),res=await response.json();if(!response.ok||res.status!=='success')throw new Error(res.msg||'No fue posible guardar el proveedor.');const saved=res.proveedor||provider,pos=providers.findIndex(p=>String(p.nombre).toLocaleLowerCase('es')===saved.nombre.toLocaleLowerCase('es'));if(pos>=0)providers[pos]={...providers[pos],...saved};else providers.push(saved);appendProviderToSelects(saved);if(providerTargetSelect){$(providerTargetSelect).val(saved.nombre).trigger('change.select2');applyProviderSelection(providerTargetSelect,saved.nombre)}message.className='provider-modal-message success';message.textContent='Proveedor guardado y seleccionado.';setTimeout(closeProviderModal,650)}catch(error){message.className='provider-modal-message error';message.textContent=error.message||'No fue posible guardar.'}finally{button.disabled=false;button.innerHTML='<i class="fa-solid fa-floppy-disk"></i> Guardar proveedor'}}
</script>
